    if not utils.file_info(config_dir) then
      local os_name = jit and jit.os or ""
      local command = os_name == "Windows" and
        {"powershell", "-NoProfile", "-Command",
          "New-Item -ItemType Directory -Force -LiteralPath $args[0] | Out-Null",
          config_dir} or
        {"mkdir", "-p", config_dir}
