package.preload["src.services.thumbnail_service"] = function(...)
local thumbnail = {}

function thumbnail.new(deps)
  local state = deps.thumbnail_state
  local viewport = deps.viewport
  local get_snapshot = deps.get_snapshot
  local utils = deps.utils
  local msg = deps.msg
  local dp = deps.dp
  local clamp = deps.clamp
  local format_time = deps.format_time
  local chapter_name_at = deps.chapter_name_at
  local enqueue_effect = deps.enqueue_effect
  local render = deps.render
  local draw_box = deps.draw_box
  local draw_text = deps.draw_text
  local text_intrinsic_width = deps.text_intrinsic_width
  local truncate_utf8_to_width = deps.truncate_utf8_to_width
  local thumbnail_service = {}

  function thumbnail_service:is_ready()
    local snapshot = get_snapshot()
    return state.available and not state.disabled and
      state.width > 0 and state.height > 0 and
      snapshot.video_present == true
  end

  function thumbnail_service:request(pos, x, y)
    if not self:is_ready() then return end
    state.visible = true
    mp.commandv("script-message-to", "thumbfast", "thumb", pos, x, y)
  end

  function thumbnail_service:clear()
    if not state.visible then return end
    state.visible = false
    if state.available then
      mp.commandv("script-message-to", "thumbfast", "clear")
    end
  end

  mp.register_script_message("thumbfast-info", function(json)
    local data = utils.parse_json(json)
    if type(data) ~= "table" or
      type(data.width) ~= "number" or type(data.height) ~= "number" then
      msg.error("thumbfast-info: invalid thumbnail information")
      return
    end

    state.width = data.width
    state.height = data.height
    state.disabled = data.disabled ~= false
    state.available = data.available == true
    render()
  end)

  local function draw_thumbnail_preview(ass, x1, seek_y, x2, pos)
    local duration = get_snapshot().duration or 0
    if not pos or duration <= 0 then return end

    local seek_w = x2 - x1
    if seek_w < dp(80) then return end

    local ratio = clamp(pos / duration, 0, 1)
    local center_x = x1 + seek_w * ratio
    local has_thumbnail = thumbnail_service:is_ready()
    local time_text = format_time(pos)
    local chapter_text = chapter_name_at(pos)
    local pill_text_size = 22
    local pill_vertical_padding = dp(4)
    local pill_horizontal_padding = dp(8)
    local pill_background_alpha = "48"
    local thumb_w = has_thumbnail and state.width or 0
    local thumb_h = has_thumbnail and state.height or 0
    local pill_h = dp(pill_text_size) + pill_vertical_padding * 2
    local gap = dp(6)
    local pill_gap = dp(6)
    local bottom_gap = dp(18)
    local margin = dp(8)
    local frame_pad = dp(1)
    local time_pill_w = text_intrinsic_width(time_text, pill_text_size) +
                pill_horizontal_padding * 2

    local max_row_w = math.max(0, viewport.w - margin * 2)
    local chapter_pill_w = 0
    if chapter_text then
      local available_chapter_w = max_row_w - time_pill_w - pill_gap
      if available_chapter_w >= dp(64) then
        local max_chapter_w = math.min(dp(300), available_chapter_w)
        chapter_text = truncate_utf8_to_width(chapter_text,
          max_chapter_w - pill_horizontal_padding * 2, pill_text_size)
        chapter_pill_w = math.min(
          max_chapter_w,
          text_intrinsic_width(chapter_text, pill_text_size) +
          pill_horizontal_padding * 2)
      else
        chapter_text = nil
      end
    end

    local row_w = time_pill_w
    if chapter_text then row_w = row_w + pill_gap + chapter_pill_w end

    local thumb_x1, thumb_y1, thumb_x2, thumb_y2 = 0, 0, 0, 0
    if has_thumbnail then
      thumb_x1 = clamp(center_x - thumb_w / 2, margin, viewport.w - margin - thumb_w)
      thumb_y1 = math.max(margin,
                    seek_y - bottom_gap - pill_h - gap - thumb_h - frame_pad * 2)
      thumb_x2 = thumb_x1 + thumb_w
      thumb_y2 = thumb_y1 + thumb_h
    end

    local row_center_x = has_thumbnail and (thumb_x1 + thumb_x2) / 2 or center_x
    local row_x1 = clamp(row_center_x - row_w / 2, margin,
               viewport.w - margin - row_w)
    local pill_y1 = has_thumbnail and (thumb_y2 + frame_pad + gap) or
                math.max(margin, seek_y - bottom_gap - pill_h)
    local pill_y2 = pill_y1 + pill_h

    local time_x1 = row_x1
    local time_x2 = time_x1 + time_pill_w
    local chapter_x1 = time_x2 + pill_gap
    local chapter_x2 = chapter_x1 + chapter_pill_w

    if has_thumbnail then
      draw_box(ass, thumb_x1 - frame_pad, thumb_y1 - frame_pad,
           thumb_x2 + frame_pad, thumb_y2 + frame_pad, 0, "#050708", "20")
      local overlay_x = math.floor(thumb_x1 + 0.5)
      local overlay_y = math.floor(thumb_y1 + 0.5)
      enqueue_effect("thumbnail-request", function()
        thumbnail_service:request(pos, overlay_x, overlay_y)
      end)
    else
      enqueue_effect("thumbnail-clear", function() thumbnail_service:clear() end)
    end

    draw_box(ass, time_x1, pill_y1, time_x2, pill_y2, pill_h / 2,
         "#050708", pill_background_alpha)
    draw_text(ass, (time_x1 + time_x2) / 2, (pill_y1 + pill_y2) / 2,
          time_text, pill_text_size, "#FFFFFF")

    if chapter_text then
      draw_box(ass, chapter_x1, pill_y1, chapter_x2, pill_y2, pill_h / 2,
           "#050708", pill_background_alpha)
      draw_text(ass, (chapter_x1 + chapter_x2) / 2,
            (pill_y1 + pill_y2) / 2, chapter_text, pill_text_size,
            "#FFFFFF")
    end
  end

  return thumbnail_service, draw_thumbnail_preview
end

return thumbnail
end

-- ===== src/services/update_service.lua =====
package.preload["src.services.update_service"] = function(...)
local update_service = {}

local CURRENT_VERSION = "0.0.6"
local REPOSITORY = "brahmkshatriya/material-osc"
local API_URL = "https://api.github.com/repos/" .. REPOSITORY .. "/releases/latest"
local CHECK_INTERVAL_SECONDS = 2 * 60 * 60

local function is_windows()
  return package.config:sub(1, 1) == "\\"
end

local function version_parts(value)
  local parts = {}
  value = tostring(value or ""):gsub("^[vV]", ""):match("^[^+-]+") or ""
  for part in value:gmatch("%d+") do parts[#parts + 1] = tonumber(part) end
  return parts
end

local function is_newer(candidate, current)
  local left, right = version_parts(candidate), version_parts(current)
  if #left == 0 or #right == 0 then return false end
  for index = 1, math.max(#left, #right) do
    local a, b = left[index] or 0, right[index] or 0
    if a ~= b then return a > b end
  end
  return false
end

local function read_file(path)
  local file = io.open(path, "rb")
  if not file then return nil end
  local contents = file:read("*a")
  file:close()
  return contents
end

local function write_file(path, contents)
  local file = io.open(path, "wb")
  if not file then return false end
  local ok = file:write(contents)
  file:close()
  return ok ~= nil
end

function update_service.new(args)
  local mp, utils, msg = args.mp, args.utils, args.msg
  local state = args.state.update
  local service = {current_version = CURRENT_VERSION}
  local preferences_path = mp.command_native({
    "expand-path", "~~/script-opts/material-osc-updater.conf"
  })

  local function render()
    if args.render then args.render() end
  end

  local function subprocess(command, callback, capture_stdout)
    mp.command_native_async({
      name = "subprocess", args = command, playback_only = false,
      capture_stdout = capture_stdout == true, capture_stderr = true
    }, function(success, result)
      local status = result and tonumber(result.status) or -1
      callback(success and status == 0, result or {})
    end)
  end

  local function http_get(url, callback)
    subprocess({"curl", "-fLsS", "--connect-timeout", "8", "--max-time", "15",
      "-H", "Accept: application/vnd.github+json", url}, function(ok, result)
      if ok or not is_windows() then callback(ok, result); return end
      subprocess({"powershell", "-NoProfile", "-Command",
        "(Invoke-WebRequest -UseBasicParsing -Headers @{Accept='application/vnd.github+json'} -Uri $args[0]).Content",
        url}, callback, true)
    end, true)
  end

  local function download(url, path, callback)
    subprocess({"curl", "-fL", "--connect-timeout", "10", "--max-time", "180",
      "-o", path, url}, function(ok, result)
      if ok or not is_windows() then callback(ok, result); return end
      subprocess({"powershell", "-NoProfile", "-Command",
        "Invoke-WebRequest -UseBasicParsing -Uri $args[0] -OutFile $args[1]",
        url, path}, callback)
    end)
  end

  local function ensure_directory(path)
    local directory = utils.split_path(path)
    if not directory or directory == "" or utils.file_info(directory) then return true end
    local command = is_windows() and
      {"powershell", "-NoProfile", "-Command",
        "New-Item -ItemType Directory -Force -LiteralPath $args[0] | Out-Null", directory} or
      {"mkdir", "-p", directory}
    local result = mp.command_native({
      name = "subprocess", args = command, playback_only = false
    })
    return result and tonumber(result.status) == 0
  end

  local function read_preferences()
    local contents = read_file(preferences_path) or ""
    local mode = contents:match("mode%s*=%s*([%a_]+)")
    if mode ~= "auto" and mode ~= "never" and mode ~= "ask" then mode = "ask" end
    local last_check = tonumber(contents:match("last_check%s*=%s*(%d+)")) or 0
    return mode, last_check
  end

  local function save_preferences(mode, last_check)
    if mode ~= "auto" and mode ~= "never" and mode ~= "ask" then return false end
    local contents = "mode=" .. mode .. "\nlast_check=" ..
      tostring(math.max(0, math.floor(tonumber(last_check) or 0))) .. "\n"
    if ensure_directory(preferences_path) and
      write_file(preferences_path, contents) then
      state.mode = mode
      state.last_check = tonumber(last_check) or 0
      return true
    else
      msg.error("could not save material-osc updater preference")
      return false
    end
  end

  local function save_mode(mode)
    local _, last_check = read_preferences()
    save_preferences(mode, last_check)
  end

  local function close()
    state.open, state.busy, state.bounds = false, false, nil
    mp.disable_key_bindings("material-osc-update-dialog")
    render()
  end

  local function show(release, notes)
    state.version = tostring(release.tag_name or ""):gsub("^[vV]", "")
    state.tag = release.tag_name
    state.notes = notes or release.body or "See the GitHub release for details."
    if state.notes:match("^%s*$") then
      state.notes = "See the GitHub release for details."
    end
    state.asset_url = nil
    for _, asset in ipairs(release.assets or {}) do
      if tostring(asset.name or "") == "material-osc.zip" then
        state.asset_url = asset.browser_download_url
        break
      end
    end
    state.open, state.busy, state.done = true, false, false
    state.scroll_index = 0
    state.error, state.dont_ask = nil, false
    mp.enable_key_bindings("material-osc-update-dialog")
    render()
  end

  local function fetch_notes(release, callback)
    local version = tostring(release.tag_name or ""):gsub("^[vV]", "")
    local url = "https://raw.githubusercontent.com/" .. REPOSITORY .. "/" ..
      tostring(release.tag_name) .. "/updates/" .. version .. ".txt"
    http_get(url, function(ok, result)
      callback(ok and result.stdout or release.body)
    end)
  end

  local function replace_file(source, target)
    local contents = read_file(source)
    if not contents then return false, "missing " .. source end
    local temporary, backup = target .. ".update", target .. ".previous"
    if not write_file(temporary, contents) then return false, "cannot write " .. temporary end
    os.remove(backup)
    local had_target = read_file(target) ~= nil
    if had_target and not os.rename(target, backup) then
      os.remove(temporary)
      return false, "cannot replace " .. target
    end
    if not os.rename(temporary, target) then
      if had_target then os.rename(backup, target) end
      os.remove(temporary)
      return false, "cannot install " .. target
    end
    os.remove(backup)
    return true
  end

  local function install_extracted(directory)
    local source_script = utils.join_path(
      utils.join_path(directory, "scripts"), "material-osc.lua")
    local ok, reason = replace_file(source_script, args.script_path)
    if not ok then return false, reason end
    ensure_directory(args.font_dir .. package.config:sub(1, 1) .. "placeholder")
    for _, font in ipairs({
      "material-osc_google_sans_flex.ttf", "material-osc_icons.otf"
    }) do
      local source = utils.join_path(utils.join_path(directory, "fonts"), font)
      local target = utils.join_path(args.font_dir, font)
      if utils.file_info(source) then
        ok, reason = replace_file(source, target)
        if not ok then return false, reason end
      end
    end
    return true
  end

  local function unpack(archive, directory, callback)
    if not ensure_directory(directory .. package.config:sub(1, 1) .. "placeholder") then
      callback(false, "could not create the temporary update directory")
      return
    end
    local command
    if is_windows() then
      command = {"powershell", "-NoProfile", "-Command",
        "Expand-Archive -Force -LiteralPath $args[0] -DestinationPath $args[1]",
        archive, directory}
    else
      command = {"unzip", "-oq", archive, "-d", directory}
    end
    subprocess(command, function(ok, result)
      if not ok and not is_windows() then
        subprocess({"tar", "-xf", archive, "-C", directory}, function(tar_ok, tar_result)
          if not tar_ok then
            callback(false, tar_result.stderr or result.stderr or "could not unpack release")
            return
          end
          callback(install_extracted(directory))
        end)
        return
      end
      if not ok then
        callback(false, result.stderr or "could not unpack release")
        return
      end
      callback(install_extracted(directory))
    end)
  end

  function service:close()
    if state.busy then return end
    if state.done then
      save_mode(state.disable_auto_update and "ask" or "auto")
    elseif state.dont_ask then
      save_mode("never")
    end
    close()
  end

  function service:toggle_dont_ask()
    if state.busy or state.done then return end
    state.dont_ask = not state.dont_ask
    render()
  end

  function service:toggle_disable_auto_update()
    if state.busy or not state.done then return end
    state.disable_auto_update = not state.disable_auto_update
    render()
  end

  function service:install(auto)
    if state.busy or state.done then return end
    if state.dont_ask or auto then save_mode("auto") end
    if not state.asset_url then
      state.error = "This release does not include an update archive."
      render()
      return
    end
    state.open, state.busy, state.error = true, true, nil
    mp.enable_key_bindings("material-osc-update-dialog")
    render()
    local base = os.tmpname()
    os.remove(base)
    local archive, directory = base .. ".zip", base .. "-material-osc"
    download(state.asset_url, archive, function(ok, result)
      if not ok then
        state.busy = false
        state.error = "Download failed. Check your internet connection and try again."
        msg.error("material-osc update download failed: " .. tostring(result.stderr or ""))
        render()
        return
      end
      unpack(archive, directory, function(installed, reason)
        os.remove(archive)
        state.busy = false
        if installed then
          state.done = true
          state.scroll_index = 0
          state.disable_auto_update = state.mode ~= "auto"
        else
          state.error = "Installation failed. " .. tostring(reason or "")
          msg.error("material-osc update installation failed: " .. tostring(reason or ""))
        end
        render()
      end)
    end)
  end

  function service:check()
    local mode, last_check = read_preferences()
    state.mode, state.last_check = mode, last_check
    local source_marker = "__MATERIAL_" .. "OSC_VERSION__"
    if CURRENT_VERSION == source_marker or CURRENT_VERSION == "dev" or
      state.mode == "never" or state.checking then return end
    local now = os.time()
    local elapsed = now - last_check
    if last_check > 0 and elapsed >= 0 and elapsed < CHECK_INTERVAL_SECONDS then
      return
    end
    save_preferences(state.mode, now)
    state.checking = true
    http_get(API_URL, function(ok, result)
      state.checking = false
      if not ok then
        msg.verbose("material-osc update check failed: " .. tostring(result.stderr or ""))
        return
      end
      local release = utils.parse_json(result.stdout or "")
      if type(release) ~= "table" or not is_newer(release.tag_name, CURRENT_VERSION) then return end
      fetch_notes(release, function(notes)
        show(release, notes)
        if state.mode == "auto" then service:install(true) end
      end)
    end)
  end

  function service:start()
    mp.set_key_bindings({{"ESC", function() service:close() end}},
      "material-osc-update-dialog", "force")
    mp.disable_key_bindings("material-osc-update-dialog")
    mp.add_timeout(2, function() service:check() end)
  end

  function service:open_release()
    local url = "https://github.com/" .. REPOSITORY .. "/releases"
    if state.tag and tostring(state.tag) ~= "" then
      url = url .. "/tag/" .. tostring(state.tag)
    end
    local os_name = jit and jit.os or ""
    local command
    if os_name == "Windows" then
      command = {"rundll32", "url.dll,FileProtocolHandler", url}
    elseif os_name == "OSX" then
      command = {"open", url}
    else
      command = {"xdg-open", url}
    end
    subprocess(command, function(ok)
      if not ok then mp.osd_message("Could not open the release page", 2) end
    end)
  end

  return service
end

update_service.is_newer = is_newer

return update_service
end

-- ===== src/services/ytdl_service.lua =====
package.preload["src.services.ytdl_service"] = function(...)
local ytdl_service = {}

local function quality_label(height, fps)
  height, fps = tonumber(height) or 0, tonumber(fps) or 0
  local label = height > 0 and (tostring(height) .. "p") or "Video"
  if height == 2160 then label = label .. " (4K)"
  elseif height == 4320 then label = label .. " (8K)" end
  if fps > 30 then label = label .. " " .. tostring(math.floor(fps + 0.5)) .. "fps" end
  return label
end

ytdl_service.quality_label = quality_label

function ytdl_service.supports(url)
  if type(url) ~= "string" then return false end
  local host = url:match("^https?://([^/%?#]+)")
  if not host then return false end
  host = host:lower():gsub(":%d+$", "")
  return host == "youtu.be" or host == "youtube.com" or
    host:match("%.youtube%.com$") ~= nil or
    host == "youtube-nocookie.com" or
    host:match("%.youtube%-nocookie%.com$") ~= nil
end

local function append_raw_options(command)
  local options = mp.get_property_native("ytdl-raw-options") or {}
  if type(options) ~= "table" then return end
  for key, value in pairs(options) do
    if value == true or value == "" then
      command[#command + 1] = "--" .. tostring(key)
    elseif value ~= false and value ~= nil then
      command[#command + 1] = "--" .. tostring(key)
      command[#command + 1] = tostring(value)
    end
  end
end

function ytdl_service.new(args)
  local state = args.runtime.ytdl

  local function select_quality(item)
    if not item or not item.selector or not state.url then return end
    local position = mp.get_property_number("time-pos", 0) or 0
    local paused = mp.get_property_native("pause") == true
    local media_title = mp.get_property("media-title", "") or ""
    state.selected_id, state.pending_selected_id = item.id, item.id
    state.pending_playback_url = item.playback_url
    local subtitles = {}
    for _, track in ipairs(mp.get_property_native("track-list") or {}) do
      if track.type == "sub" and track.external and track["external-filename"] then
        subtitles[#subtitles + 1] = {
          url = track["external-filename"], title = track.title,
          language = track.lang, selected = track.selected == true
        }
      end
    end
    state.pending_subtitles = {
      tracks = subtitles,
      visible = mp.get_property_native("sub-visibility") ~= false
    }
    local load_options = {
      start = tostring(position), pause = paused and "yes" or "no"
    }
    if not item.playback_url then
      mp.set_property("ytdl-format", item.selector)
      load_options["ytdl-format"] = item.selector
    end
    if media_title ~= "" then load_options["force-media-title"] = media_title end
    args.runtime.loading.quality_switching = true
    args.runtime.loading.started_ms = mp.get_time() * 1000
    args.render()
    mp.command_native({name = "loadfile", url = item.playback_url or state.url,
      flags = "replace", options = load_options})
  end

  local function restore_subtitles()
    local pending = state.pending_subtitles
    if type(pending) ~= "table" then return end
    state.pending_subtitles = nil
    for _, subtitle in ipairs(pending.tracks or {}) do
      mp.commandv("sub-add", subtitle.url, subtitle.selected and "select" or "auto",
        subtitle.title or "Subtitle", subtitle.language or "und")
    end
    mp.set_property_native("sub-visibility", pending.visible ~= false)
  end

  local function attach_caption(item)
    if not item or not item.url or state.caption_loading_id then return end
    state.caption_request_id = state.caption_request_id + 1
    local request_id = state.caption_request_id
    state.caption_loading_id = item.id
    args.render()
    mp.command_native_async({"sub-add", item.url, "select",
      item.track_title or item.label, item.language}, function(success, result)
      if request_id ~= state.caption_request_id then return end
      state.caption_loading_id = nil
      if success and (not result or result.status == nil or result.status == 0) then
        args.set_settings_page("subtitles")
      else
        mp.osd_message("Failed to load auto subtitle", 3)
      end
      args.render()
    end)
  end

  local function load_qualities()
    local path = mp.get_property("path", "") or ""
    if state.pending_playback_url and path == state.pending_playback_url then
      state.selected_id = state.pending_selected_id or state.selected_id
      state.pending_selected_id, state.pending_playback_url = nil, nil
      return
    end
    if not ytdl_service.supports(path) then
      state.active, state.source, state.url = false, nil, nil
      state.items, state.caption_items = {}, {}
      state.selected_id, state.pending_selected_id = nil, nil
      state.pending_playback_url = nil
      return
    end
    if state.active and state.url == path and #state.items > 0 then
      state.selected_id = state.pending_selected_id or state.selected_id
      state.pending_selected_id = nil
      return
    end
    state.request_id = state.request_id + 1
    local request_id = state.request_id
    state.items, state.caption_items, state.selected_id = {}, {}, nil
    state.active, state.source, state.url = true, "youtube", path
    local command = {"yt-dlp", "--dump-single-json", "--no-playlist", "--no-warnings", path}
    append_raw_options(command)
    mp.command_native_async({name = "subprocess", args = command,
      playback_only = false, capture_stdout = true, capture_stderr = true},
      function(success, result)
        if request_id ~= state.request_id or not success or not result or
          result.status ~= 0 then return end
        local data = args.utils.parse_json(result.stdout or "")
        if not data or type(data.formats) ~= "table" then return end
        local best = {}
        for _, format in ipairs(data.formats) do
          local height, width, fps = tonumber(format.height),
            tonumber(format.width), tonumber(format.fps)
          local id = tostring(format.format_id or "")
          if height and width and id ~= "" and format.vcodec and format.vcodec ~= "none" then
            local rounded_fps = fps and math.floor(fps + 0.5) or 0
            local key = tostring(height)
            local score = rounded_fps * 10000000 +
              (tonumber(format.tbr) or tonumber(format.vbr) or 0)
            if not best[key] or score > best[key].score then
              best[key] = {score = score, width = width, height = height,
                fps = rounded_fps, format_id = id,
                has_audio = format.acodec and format.acodec ~= "none",
                playback_url = format.protocol and
                  format.protocol:match("^m3u8") and
                  format.manifest_url == path and format.url or nil}
            end
          end
        end
        local items = {}
        for key, entry in pairs(best) do
          items[#items + 1] = {id = "ytdl:" .. key,
            label = quality_label(entry.height, entry.fps),
            stream_quality = true, source = "youtube",
            selector = entry.has_audio and entry.format_id or
              (entry.format_id .. "+bestaudio/best"),
            playback_url = entry.playback_url,
            width = entry.width, height = entry.height, fps = entry.fps}
        end
        table.sort(items, function(a, b)
          if a.height ~= b.height then return a.height > b.height end
          return a.fps > b.fps
        end)
        state.items = items
        local captions = {}
        for language, formats in pairs(data.automatic_captions or {}) do
          local selected
          for _, caption in ipairs(formats) do
            if caption.ext == "vtt" then selected = caption break end
          end
          selected = selected or formats[1]
          if selected and selected.url then
            local name = selected.name or tostring(language)
            captions[#captions + 1] = {id = "auto:" .. tostring(language),
              label = name, track_title = name .. " (Auto)",
              language = tostring(language), url = selected.url}
          end
        end
        table.sort(captions, function(a, b) return a.label < b.label end)
        state.caption_items = captions
        args.render()
      end)
  end

  return {select_quality = select_quality, restore_subtitles = restore_subtitles,
    attach_caption = attach_caption, load_qualities = load_qualities}
end

return ytdl_service
end

