    function node:draw(ass, bounds)
      draw_box(ass, bounds.x, bounds.y, bounds.x2, bounds.y2,
        dp(30), "#050708", self.panel_alpha)
      draw_node(self.header, ass, Rect({x = bounds.x, y = bounds.y,
