  if b1 < 0xF0 and b2 and b3 then
    return (b1 - 0xE0) * 0x1000 + (b2 - 0x80) * 0x40 + b3 - 0x80
  end
  if b2 and b3 and b4 then
    return (b1 - 0xF0) * 0x40000 + (b2 - 0x80) * 0x1000 +
      (b3 - 0x80) * 0x40 + b4 - 0x80
